  const groups = paren_string.split(' ');
  const result = [];

  // Loop through each group
  for (let i = 0; i < groups.length; i++) {
    const group = groups[i];
    let maxDepth = 0;
    let currentDepth = 0;

    // Loop through each character in the group
    for (let j = 0; j < group.length; j++) {
      const char = group[j];

      // If the character is an opening parenthesis, increment the current depth
      if (char === '(') {
        currentDepth++;
        // If the current depth is greater than the maximum depth, update the maximum depth
        if (currentDepth > maxDepth) {
          maxDepth = currentDepth;
